// مثال باستخدام ImGui
void DrawSceneHierarchy() {
    ImGui::Begin("هيكل المشهد");

    // البحث
    static char searchBuffer[64] = "";
    ImGui::InputTextWithHint("##search", "بحث...", searchBuffer, IM_ARRAYSIZE(searchBuffer));
    ImGui::Separator();

    // الكائن الجذر
    if (ImGui::TreeNodeEx("المشهد", ImGuiTreeNodeFlags_DefaultOpen)) {
        // مجلد الإضاءة
        if (ImGui::TreeNodeEx("الإضاءة", ImGuiTreeNodeFlags_DefaultOpen)) {
            for (auto& light : scene.lights) {
                bool isSelected = (selectedEntity == light.id);
                if (ImGui::Selectable(light.name, isSelected)) {
                    selectedEntity = light.id;
                }
                if (ImGui::BeginDragDropSource()) {
                    ImGui::SetDragDropPayload("ENTITY", &light.id, sizeof(int));
                    ImGui::Text("%s", light.name);
                    ImGui::EndDragDropSource();
                }
            }
            ImGui::TreePop();
        }

        // مجلد الكائنات
        if (ImGui::TreeNodeEx("الكائنات", ImGuiTreeNodeFlags_DefaultOpen)) {
            DrawEntityNode(scene.rootEntity);
            ImGui::TreePop();
        }

        ImGui::TreePop();
    }

    // قائمة سياقية
    if (ImGui::BeginPopupContextWindow()) {
        if (ImGui::MenuItem("إضافة كائن فارغ")) {
            CreateEmptyEntity();
        }
        if (ImGui::MenuItem("إضافة مصدر ضوء")) {
            CreateLight();
        }
        ImGui::Separator();
        if (ImGui::MenuItem("حذف المحدد", nullptr, false, selectedEntity != -1)) {
            DeleteEntity(selectedEntity);
        }
        ImGui::EndPopup();
    }

    ImGui::End();
}

void DrawEntityNode(Entity& entity) {
    ImGuiTreeNodeFlags flags = ImGuiTreeNodeFlags_OpenOnArrow;
    if (entity.children.empty()) flags |= ImGuiTreeNodeFlags_Leaf;
    if (selectedEntity == entity.id) flags |= ImGuiTreeNodeFlags_Selected;

    bool isOpen = ImGui::TreeNodeEx((void*)(intptr_t)entity.id, flags, "%s", entity.name);

    if (ImGui::IsItemClicked()) {
        selectedEntity = entity.id;
    }

    // السحب والإفلات
    if (ImGui::BeginDragDropSource()) {
        ImGui::SetDragDropPayload("ENTITY", &entity.id, sizeof(int));
        ImGui::Text("%s", entity.name);
        ImGui::EndDragDropSource();
    }

    if (ImGui::BeginDragDropTarget()) {
        if (const ImGuiPayload* payload = ImGui::AcceptDragDropPayload("ENTITY")) {
            int draggedId = *(const int*)payload->Data;
            ReparentEntity(draggedId, entity.id);
        }
        ImGui::EndDragDropTarget();
    }

    if (isOpen) {
        for (auto& child : entity.children) {
            DrawEntityNode(child);
        }
        ImGui::TreePop();
    }
}

// مثال باستخدام ImGui
void DrawInspector() {
    ImGui::Begin("الخصائص");

    if (selectedEntity == -1) {
        ImGui::Text("لا يوجد كائن محدد");
        ImGui::End();
        return;
    }

    Entity& entity = GetEntity(selectedEntity);

    // اسم الكائن
    char nameBuffer[64];
    strcpy(nameBuffer, entity.name);
    if (ImGui::InputText("##name", nameBuffer, IM_ARRAYSIZE(nameBuffer))) {
        strcpy(entity.name, nameBuffer);
    }

    ImGui::Separator();

    // التحويل (Transform)
    if (ImGui::CollapsingHeader("التحويل", ImGuiTreeNodeFlags_DefaultOpen)) {
        // الموقع
        ImGui::Text("الموقع");
        ImGui::DragFloat3("##position", &entity.transform.position.x, 0.1f);

        // الدوران
        ImGui::Text("الدوران");
        Vector3 eulerRotation = QuaternionToEuler(entity.transform.rotation);
        if (ImGui::DragFloat3("##rotation", &eulerRotation.x, 1.0f)) {
            entity.transform.rotation = EulerToQuaternion(eulerRotation);
        }

        // الحجم
        ImGui::Text("الحجم");
        ImGui::DragFloat3("##scale", &entity.transform.scale.x, 0.05f);
    }

    // المكونات
    if (ImGui::CollapsingHeader("المكونات")) {
        // Mesh Renderer
        if (entity.meshRenderer) {
            if (ImGui::TreeNode("Mesh Renderer")) {
                ImGui::Text("Mesh: %s", entity.meshRenderer->meshName);
                ImGui::Text("Material: %s", entity.meshRenderer->materialName);
                ImGui::Checkbox("Cast Shadow", &entity.meshRenderer->castShadow);
                ImGui::TreePop();
            }
        }

        // Light Component
        if (entity.light) {
            if (ImGui::TreeNode("Light")) {
                const char* lightTypes[] = { "Directional", "Point", "Spot" };
                ImGui::Combo("Type", &entity.light->type, lightTypes, 3);
                ImGui::ColorEdit3("Color", &entity.light->color.x);
                ImGui::DragFloat("Intensity", &entity.light->intensity, 0.1f, 0, 10);
                ImGui::TreePop();
            }
        }
    }

    // زر إضافة مكون
    ImGui::Separator();
    if (ImGui::Button("إضافة مكون", ImVec2(-1, 0))) {
        ImGui::OpenPopup("AddComponent");
    }

    if (ImGui::BeginPopup("AddComponent")) {
        if (ImGui::MenuItem("Mesh Renderer")) AddComponent<MeshRenderer>(entity);
        if (ImGui::MenuItem("Light")) AddComponent<Light>(entity);
        if (ImGui::MenuItem("Audio Source")) AddComponent<AudioSource>(entity);
        ImGui::EndPopup();
    }

    ImGui::End();
}

enum class LogType {
    Info,
    Warning,
    Error,
    Success
};

struct LogEntry {
    LogType type;
    std::string message;
    std::string timestamp;
};

std::vector<LogEntry> consoleLogs;
bool showInfo = true, showWarning = true, showError = true;

void AddLog(LogType type, const char* format, ...) {
    LogEntry entry;
    entry.type = type;

    // الوقت
    time_t now = time(nullptr);
    struct tm* timeinfo = localtime(&now);
    char timeBuffer[16];
    strftime(timeBuffer, sizeof(timeBuffer), "%H:%M:%S", timeinfo);
    entry.timestamp = timeBuffer;

    // الرسالة
    char buffer[512];
    va_list args;
    va_start(args, format);
    vsnprintf(buffer, sizeof(buffer), format, args);
    va_end(args);
    entry.message = buffer;

    consoleLogs.push_back(entry);

    // الحفاظ على آخر 500 رسالة فقط
    if (consoleLogs.size() > 500) {
        consoleLogs.erase(consoleLogs.begin());
    }
}

void DrawConsole() {
    ImGui::Begin("الكونسول");

    // شريط الأدوات
    ImGui::Checkbox("Info", &showInfo);
    ImGui::SameLine();
    ImGui::Checkbox("Warning", &showWarning);
    ImGui::SameLine();
    ImGui::Checkbox("Error", &showError);
    ImGui::SameLine();

    // زر المسح
    if (ImGui::Button("مسح")) {
        consoleLogs.clear();
    }
    ImGui::SameLine();

    // البحث
    static char searchBuffer[64] = "";
    ImGui::InputTextWithHint("##search", "بحث...", searchBuffer, IM_ARRAYSIZE(searchBuffer));

    ImGui::Separator();

    // الرسائل
    ImGui::BeginChild("Logs", ImVec2(0, 0), false, ImGuiWindowFlags_HorizontalScrollbar);

    for (const auto& log : consoleLogs) {
        // تصفية حسب النوع
        if (!showInfo && log.type == LogType::Info) continue;
        if (!showWarning && log.type == LogType::Warning) continue;
        if (!showError && log.type == LogType::Error) continue;

        // تصفية البحث
        if (strlen(searchBuffer) > 0 &&
            log.message.find(searchBuffer) == std::string::npos) {
            continue;
        }

        // اللون حسب النوع
        ImVec4 color;
        const char* prefix;
        switch (log.type) {
            case LogType::Info:
                color = ImVec4(0.7f, 0.7f, 0.7f, 1.0f);
                prefix = "[INFO]";
                break;
            case LogType::Warning:
                color = ImVec4(1.0f, 0.8f, 0.0f, 1.0f);
                prefix = "[WARN]";
                break;
            case LogType::Error:
                color = ImVec4(1.0f, 0.3f, 0.3f, 1.0f);
                prefix = "[ERROR]";
                break;
            case LogType::Success:
                color = ImVec4(0.3f, 1.0f, 0.3f, 1.0f);
                prefix = "[OK]";
                break;
        }

        ImGui::TextColored(color, "%s [%s] %s",
                          log.timestamp.c_str(), prefix, log.message.c_str());
    }

    // التمرير التلقائي للأسفل
    if (ImGui::GetScrollY() >= ImGui::GetScrollMaxY()) {
        ImGui::SetScrollHereY(1.0f);
    }

    ImGui::EndChild();
    ImGui::End();
}

struct PerformanceData {
    static const int MAX_SAMPLES = 120;
    float fpsHistory[MAX_SAMPLES];
    float frameTimeHistory[MAX_SAMPLES];
    int currentIndex;

    float currentFPS;
    float averageFPS;
    float minFPS, maxFPS;
};

void UpdatePerformanceData(PerformanceData& data) {
    data.currentFPS = 1.0f / GetFrameTime();

    data.fpsHistory[data.currentIndex] = data.currentFPS;
    data.frameTimeHistory[data.currentIndex] = GetFrameTime() * 1000.0f; // ms

    data.currentIndex = (data.currentIndex + 1) % PerformanceData::MAX_SAMPLES;

    // حساب المتوسط والحدود
    float sum = 0;
    data.minFPS = 1000;
    data.maxFPS = 0;
    for (int i = 0; i < PerformanceData::MAX_SAMPLES; i++) {
        sum += data.fpsHistory[i];
        if (data.fpsHistory[i] < data.minFPS) data.minFPS = data.fpsHistory[i];
        if (data.fpsHistory[i] > data.maxFPS) data.maxFPS = data.fpsHistory[i];
    }
    data.averageFPS = sum / PerformanceData::MAX_SAMPLES;
}

void DrawPerformanceGraph(const PerformanceData& data, Rectangle bounds) {
    // خلفية
    DrawRectangleRec(bounds, Color{20, 20, 25});
    DrawRectangleLinesEx(bounds, 1, Color{60, 60, 70});

    float graphHeight = bounds.height - 30;
    float graphWidth = bounds.width - 20;
    Vector2 graphPos = {bounds.x + 10, bounds.y + 10};

    // خطوط الشبكة
    for (int i = 0; i <= 4; i++) {
        float y = graphPos.y + (graphHeight / 4) * i;
        DrawLine(graphPos.x, y, graphPos.x + graphWidth, y, Color{40, 40, 50});

        // تسميات FPS
        int fpsLabel = 120 - i * 30;
        char label[8];
        sprintf(label, "%d", fpsLabel);
        DrawText(label, bounds.x + 2, y - 6, 8, Color{100, 100, 100});
    }

    // خط الهدف (60 FPS)
    float target60Y = graphPos.y + graphHeight * (1.0f - 60.0f / 120.0f);
    DrawLine(graphPos.x, target60Y, graphPos.x + graphWidth, target60Y, Color{50, 150, 50, 100});

    // رسم المنحنى
    for (int i = 0; i < PerformanceData::MAX_SAMPLES - 1; i++) {
        int idx1 = (data.currentIndex + i) % PerformanceData::MAX_SAMPLES;
        int idx2 = (data.currentIndex + i + 1) % PerformanceData::MAX_SAMPLES;

        float x1 = graphPos.x + (float)i / PerformanceData::MAX_SAMPLES * graphWidth;
        float x2 = graphPos.x + (float)(i + 1) / PerformanceData::MAX_SAMPLES * graphWidth;

        float y1 = graphPos.y + graphHeight * (1.0f - data.fpsHistory[idx1] / 120.0f);
        float y2 = graphPos.y + graphHeight * (1.0f - data.fpsHistory[idx2] / 120.0f);

        // لون يتغير حسب FPS
        Color lineColor = data.fpsHistory[idx1] >= 60 ? Color{50, 200, 50} :
                         data.fpsHistory[idx1] >= 30 ? Color{200, 200, 50} :
                                                        Color{200, 50, 50};

        DrawLine(x1, y1, x2, y2, lineColor);
    }

    // الإحصائيات
    char stats[128];
    sprintf(stats, "FPS: %.0f | Avg: %.0f | Min: %.0f | Max: %.0f",
            data.currentFPS, data.averageFPS, data.minFPS, data.maxFPS);
    DrawText(stats, graphPos.x, bounds.y + bounds.height - 18, 10, Color{200, 200, 200});
}

