cmake_minimum_required(VERSION 3.20)
project(SceneImageCameraSimulator CXX)

set(CMAKE_CXX_STANDARD 17)
set(CMAKE_CXX_STANDARD_REQUIRED ON)

find_package(SDL3 REQUIRED)

set(IMGUI_DIR ${CMAKE_SOURCE_DIR}/third-party/imgui)

add_library(imgui STATIC
    ${IMGUI_DIR}/imgui.cpp
    ${IMGUI_DIR}/imgui_draw.cpp
    ${IMGUI_DIR}/imgui_tables.cpp
    ${IMGUI_DIR}/imgui_widgets.cpp
    ${IMGUI_DIR}/backends/imgui_impl_sdl3.cpp
    ${IMGUI_DIR}/backends/imgui_impl_sdlrenderer3.cpp
)

target_include_directories(imgui PUBLIC
    ${IMGUI_DIR}
    ${IMGUI_DIR}/backends
)

target_link_libraries(imgui PUBLIC SDL3::SDL3)

add_executable(SceneImageCameraSimulator
    src/main.cpp
    src/scene_camera.cpp
)

target_include_directories(SceneImageCameraSimulator PRIVATE src)
target_link_libraries(SceneImageCameraSimulator PRIVATE SDL3::SDL3 imgui)

