// 📄 src/scene_types.hpp — بيانات المشهد والكاميرا
// ═══════════════════════════════════════════
#pragma once

#include <SDL3/SDL.h>
#include <imgui.h>
#include <string>
#include <vector>

struct Vec2 {
    float x = 0.0f;
    float y = 0.0f;
};

struct SpriteNode {
    int id = 0;
    std::string name;
    Vec2 position;
    Vec2 size;
    ImVec4 tint = ImVec4(1, 1, 1, 1);
    bool visible = true;
};

struct CameraState {
    Vec2 position{0.0f, 0.0f};
    float zoom = 1.0f;
    float moveSpeed = 420.0f;
    bool dragging = false;
    Vec2 dragOriginMouse{0.0f, 0.0f};
    Vec2 dragOriginCamera{0.0f, 0.0f};
};

struct EditorState {
    std::vector<SpriteNode> sprites;
    int selectedSpriteId = 1;
    CameraState camera;
    bool showGrid = true;
    bool showBounds = true;
    bool requestQuit = false;
};

void BuildDemoScene(EditorState& state);
void HandleCameraInput(EditorState& state, float deltaTime);
void DrawSceneHierarchy(EditorState& state);
void DrawSceneInspector(EditorState& state);
void DrawCameraSimulatorPanel(EditorState& state, float deltaTime);
void DrawSceneViewport(EditorState& state);

// ═══════════════════════════════════════════
// 📄 src/scene_camera.cpp — منطق الكاميرا ولوحات المحرر
// ═══════════════════════════════════════════
#include "scene_types.hpp"

#include <algorithm>
#include <cmath>

namespace {
SpriteNode* FindSelectedSprite(EditorState& state) {
    for (auto& sprite : state.sprites) {
        if (sprite.id == state.selectedSpriteId) {
            return &sprite;
        }
    }
    return nullptr;
}

ImVec2 WorldToScreen(const Vec2& world, const CameraState& camera, const ImVec2& viewportOrigin, const ImVec2& viewportSize) {
    const float centeredX = (world.x - camera.position.x) * camera.zoom + viewportOrigin.x + viewportSize.x * 0.5f;
    const float centeredY = (world.y - camera.position.y) * camera.zoom + viewportOrigin.y + viewportSize.y * 0.5f;
    return ImVec2(centeredX, centeredY);
}

bool IsViewportHovered() {
    return ImGui::IsWindowHovered(ImGuiHoveredFlags_AllowWhenBlockedByActiveItem);
}
}

void BuildDemoScene(EditorState& state) {
    state.sprites = {
        {1, "Background", {-420.0f, -240.0f}, {840.0f, 480.0f}, ImVec4(0.22f, 0.24f, 0.30f, 1.0f), true},
        {2, "Mountains", {-360.0f, -120.0f}, {720.0f, 180.0f}, ImVec4(0.34f, 0.42f, 0.58f, 1.0f), true},
        {3, "Player", {-80.0f, 40.0f}, {96.0f, 128.0f}, ImVec4(0.90f, 0.72f, 0.25f, 1.0f), true},
        {4, "Enemy", {220.0f, 60.0f}, {96.0f, 128.0f}, ImVec4(0.75f, 0.30f, 0.35f, 1.0f), true},
        {5, "Foreground Tree", {340.0f, -10.0f}, {120.0f, 220.0f}, ImVec4(0.20f, 0.58f, 0.33f, 1.0f), true}
    };

    state.selectedSpriteId = 3;
    state.camera.position = {0.0f, 0.0f};
    state.camera.zoom = 1.0f;
}

void HandleCameraInput(EditorState& state, float deltaTime) {
    ImGuiIO& io = ImGui::GetIO();
    CameraState& camera = state.camera;
    const float moveStep = camera.moveSpeed * deltaTime / std::max(camera.zoom, 0.001f);

    if (!io.WantCaptureKeyboard) {
        if (ImGui::IsKeyDown(ImGuiKey_W) || ImGui::IsKeyDown(ImGuiKey_UpArrow)) camera.position.y -= moveStep;
        if (ImGui::IsKeyDown(ImGuiKey_S) || ImGui::IsKeyDown(ImGuiKey_DownArrow)) camera.position.y += moveStep;
        if (ImGui::IsKeyDown(ImGuiKey_A) || ImGui::IsKeyDown(ImGuiKey_LeftArrow)) camera.position.x -= moveStep;
        if (ImGui::IsKeyDown(ImGuiKey_D) || ImGui::IsKeyDown(ImGuiKey_RightArrow)) camera.position.x += moveStep;
    }

    camera.zoom += io.MouseWheel * 0.08f * camera.zoom;
    camera.zoom = std::clamp(camera.zoom, 0.25f, 3.5f);

    if (ImGui::IsMouseClicked(ImGuiMouseButton_Middle) && !io.WantCaptureMouse) {
        camera.dragging = true;
        camera.dragOriginMouse = {io.MousePos.x, io.MousePos.y};
        camera.dragOriginCamera = camera.position;
    }

    if (!ImGui::IsMouseDown(ImGuiMouseButton_Middle)) {
        camera.dragging = false;
    }

    if (camera.dragging) {
        const Vec2 mouseDelta{io.MousePos.x - camera.dragOriginMouse.x, io.MousePos.y - camera.dragOriginMouse.y};
        camera.position.x = camera.dragOriginCamera.x - mouseDelta.x / camera.zoom;
        camera.position.y = camera.dragOriginCamera.y - mouseDelta.y / camera.zoom;
    }
}

void DrawSceneHierarchy(EditorState& state) {
    ImGui::Begin("Scene Hierarchy");
    ImGui::TextUnformatted("عناصر مشهد الصورة");
    ImGui::Separator();

    for (const auto& sprite : state.sprites) {
        const bool selected = sprite.id == state.selectedSpriteId;
        if (ImGui::Selectable(sprite.name.c_str(), selected)) {
            state.selectedSpriteId = sprite.id;
        }
    }

    ImGui::End();
}

void DrawSceneInspector(EditorState& state) {
    ImGui::Begin("Inspector");
    SpriteNode* sprite = FindSelectedSprite(state);
    if (!sprite) {
        ImGui::TextUnformatted("لا يوجد عنصر محدد.");
        ImGui::End();
        return;
    }

    ImGui::Text("العنصر: %s", sprite->name.c_str());
    ImGui::Checkbox("Visible", &sprite->visible);
    ImGui::DragFloat2("Position", &sprite->position.x, 1.0f);
    ImGui::DragFloat2("Size", &sprite->size.x, 1.0f, 8.0f, 2000.0f);
    ImGui::ColorEdit4("Tint", &sprite->tint.x);
    ImGui::TextDisabled("هذا التعديل يغيّر بيانات العنصر، لا الكاميرا.");
    ImGui::End();
}

void DrawCameraSimulatorPanel(EditorState& state, float deltaTime) {
    ImGui::Begin("Camera Simulator");
    ImGui::Text("Delta Time: %.4f", deltaTime);
    ImGui::DragFloat2("Camera Position", &state.camera.position.x, 1.0f);
    ImGui::SliderFloat("Zoom", &state.camera.zoom, 0.25f, 3.5f, "%.2f x");
    ImGui::DragFloat("Move Speed", &state.camera.moveSpeed, 5.0f, 50.0f, 2000.0f);
    ImGui::Checkbox("Show Grid", &state.showGrid);
    ImGui::Checkbox("Show Bounds", &state.showBounds);
    ImGui::Separator();
    ImGui::BulletText("WASD / الأسهم: تحريك الكاميرا");
    ImGui::BulletText("Mouse Wheel: تقريب / إبعاد");
    ImGui::BulletText("Middle Mouse Drag: سحب مباشر للمشهد");
    if (ImGui::Button("Reset Camera")) {
        state.camera.position = {0.0f, 0.0f};
        state.camera.zoom = 1.0f;
    }
    ImGui::End();
}

void DrawSceneViewport(EditorState& state) {
    ImGui::Begin("Scene Viewport");
    const ImVec2 viewportMin = ImGui::GetCursorScreenPos();
    const ImVec2 viewportSize = ImGui::GetContentRegionAvail();
    const ImVec2 viewportMax = ImVec2(viewportMin.x + viewportSize.x, viewportMin.y + viewportSize.y);
    ImDrawList* drawList = ImGui::GetWindowDrawList();

    drawList->AddRectFilled(viewportMin, viewportMax, IM_COL32(24, 27, 35, 255));

    if (state.showGrid) {
        const float gridStep = 64.0f * state.camera.zoom;
        for (float x = std::fmod(-state.camera.position.x * state.camera.zoom, gridStep); x < viewportSize.x; x += gridStep) {
            drawList->AddLine(ImVec2(viewportMin.x + x, viewportMin.y), ImVec2(viewportMin.x + x, viewportMax.y), IM_COL32(55, 60, 72, 255));
        }
        for (float y = std::fmod(-state.camera.position.y * state.camera.zoom, gridStep); y < viewportSize.y; y += gridStep) {
            drawList->AddLine(ImVec2(viewportMin.x, viewportMin.y + y), ImVec2(viewportMax.x, viewportMin.y + y), IM_COL32(55, 60, 72, 255));
        }
    }

    for (const auto& sprite : state.sprites) {
        if (!sprite.visible) {
            continue;
        }

        const ImVec2 topLeft = WorldToScreen(sprite.position, state.camera, viewportMin, viewportSize);
        const ImVec2 bottomRight = ImVec2(topLeft.x + sprite.size.x * state.camera.zoom, topLeft.y + sprite.size.y * state.camera.zoom);
        const ImU32 fill = ImGui::ColorConvertFloat4ToU32(sprite.tint);
        const bool selected = sprite.id == state.selectedSpriteId;

        drawList->AddRectFilled(topLeft, bottomRight, fill, 6.0f);
        drawList->AddText(ImVec2(topLeft.x + 8.0f, topLeft.y + 8.0f), IM_COL32(255,255,255,255), sprite.name.c_str());

        if (state.showBounds || selected) {
            drawList->AddRect(topLeft, bottomRight, selected ? IM_COL32(255, 220, 120, 255) : IM_COL32(180, 190, 210, 255), 6.0f, 0, selected ? 3.0f : 1.0f);
        }
    }

    drawList->AddRect(viewportMin, viewportMax, IM_COL32(88, 96, 118, 255));
    ImGui::InvisibleButton("scene-canvas", viewportSize);

    if (IsViewportHovered() && ImGui::IsMouseClicked(ImGuiMouseButton_Left)) {
        const ImVec2 mouse = ImGui::GetIO().MousePos;
        for (auto it = state.sprites.rbegin(); it != state.sprites.rend(); ++it) {
            const ImVec2 topLeft = WorldToScreen(it->position, state.camera, viewportMin, viewportSize);
            const ImVec2 bottomRight = ImVec2(topLeft.x + it->size.x * state.camera.zoom, topLeft.y + it->size.y * state.camera.zoom);
            if (mouse.x >= topLeft.x && mouse.x <= bottomRight.x && mouse.y >= topLeft.y && mouse.y <= bottomRight.y) {
                state.selectedSpriteId = it->id;
                break;
            }
        }
    }

    ImGui::End();
}

