// 📄 src/main.cpp — التهيئة والحلقة الرئيسية
// ═══════════════════════════════════════════
#include <SDL3/SDL.h>
#include <imgui.h>
#include <imgui_impl_sdl3.h>
#include <imgui_impl_sdlrenderer3.h>
#include <cstdio>

#include "scene_types.hpp"

int main(int, char**) {
    if (!SDL_Init(SDL_INIT_VIDEO | SDL_INIT_TIMER)) {
        std::printf("فشل SDL_Init: %s\n", SDL_GetError());
        return 1;
    }

    SDL_Window* window = SDL_CreateWindow("Scene Image Camera Simulator", 1440, 860, SDL_WINDOW_RESIZABLE);
    if (!window) {
        std::printf("فشل إنشاء النافذة: %s\n", SDL_GetError());
        SDL_Quit();
        return 1;
    }

    SDL_Renderer* renderer = SDL_CreateRenderer(window, nullptr);
    if (!renderer) {
        std::printf("فشل إنشاء SDL_Renderer: %s\n", SDL_GetError());
        SDL_DestroyWindow(window);
        SDL_Quit();
        return 1;
    }

    IMGUI_CHECKVERSION();
    ImGui::CreateContext();
    ImGuiIO& io = ImGui::GetIO();
    io.ConfigFlags |= ImGuiConfigFlags_DockingEnable;
    io.ConfigFlags |= ImGuiConfigFlags_NavEnableKeyboard;

    ImGui::StyleColorsDark();
    ImGui_ImplSDL3_InitForSDLRenderer(window, renderer);
    ImGui_ImplSDLRenderer3_Init(renderer);

    EditorState state;
    BuildDemoScene(state);

    Uint64 lastCounter = SDL_GetPerformanceCounter();
    bool running = true;

    while (running) {
        SDL_Event event;
        while (SDL_PollEvent(&event)) {
            ImGui_ImplSDL3_ProcessEvent(&event);
            if (event.type == SDL_EVENT_QUIT) {
                running = false;
            }
        }

        const Uint64 now = SDL_GetPerformanceCounter();
        const float deltaTime = static_cast<float>((now - lastCounter) / static_cast<double>(SDL_GetPerformanceFrequency()));
        lastCounter = now;

        ImGui_ImplSDLRenderer3_NewFrame();
        ImGui_ImplSDL3_NewFrame();
        ImGui::NewFrame();

        HandleCameraInput(state, deltaTime);

        ImGui::DockSpaceOverViewport(ImGui::GetMainViewport());
        DrawSceneHierarchy(state);
        DrawSceneInspector(state);
        DrawCameraSimulatorPanel(state, deltaTime);
        DrawSceneViewport(state);

        if (state.requestQuit) {
            running = false;
        }

        ImGui::Render();
        SDL_SetRenderDrawColor(renderer, 16, 18, 24, 255);
        SDL_RenderClear(renderer);
        ImGui_ImplSDLRenderer3_RenderDrawData(ImGui::GetDrawData());
        SDL_RenderPresent(renderer);
    }

    ImGui_ImplSDLRenderer3_Shutdown();
    ImGui_ImplSDL3_Shutdown();
    ImGui::DestroyContext();
    SDL_DestroyRenderer(renderer);
    SDL_DestroyWindow(window);
    SDL_Quit();
    return 0;
}

