// 📄 src/plugin_api.hpp — العقد المشترك بين التطبيق والإضافات
// ═══════════════════════════════════════════
#pragma once
#include <SDL3/SDL.h>
#include <imgui.h>

struct AppContext {
    SDL_Window* window = nullptr;
    SDL_Renderer* renderer = nullptr;
    float deltaTime = 0.0f;
};

// أي إضافة يجب أن ترث هذا العقد حتى يتعامل معها التطبيق الرئيسي بشكل موحد.
struct IGamePlugin {
    virtual ~IGamePlugin() = default;
    virtual const char* GetName() const = 0;
    virtual void OnLoad(AppContext& app) = 0;
    virtual void OnEvent(const SDL_Event& event, AppContext& app) = 0;
    virtual void OnUpdate(AppContext& app) = 0;
    virtual void OnRenderUI(AppContext& app) = 0;
    virtual void OnUnload(AppContext& app) = 0;
};

// التواقيع الرسمية التي سيبحث عنها التطبيق داخل كل مكتبة مشتركة.
using CreatePluginFn = IGamePlugin* (*)();
using DestroyPluginFn = void (*)(IGamePlugin*);

// ═══════════════════════════════════════════
// 📄 src/plugin_manager.hpp — مدير التحميل الديناميكي
// ═══════════════════════════════════════════
#pragma once
#include "plugin_api.hpp"
#include <string>
#include <vector>

struct LoadedPlugin {
    std::string filePath;
    SDL_SharedObject* libraryHandle = nullptr;
    CreatePluginFn create = nullptr;
    DestroyPluginFn destroy = nullptr;
    IGamePlugin* instance = nullptr;
};

class PluginManager {
public:
    bool LoadAllFromDirectory(const std::string& folderPath, AppContext& app);
    void DispatchEvent(const SDL_Event& event, AppContext& app);
    void UpdateAll(AppContext& app);
    void RenderAllUI(AppContext& app);
    void UnloadAll(AppContext& app);
    std::size_t Count() const { return plugins.size(); }

private:
    bool LoadSinglePlugin(const std::string& filePath, AppContext& app);
    std::vector<LoadedPlugin> plugins;
};

// ═══════════════════════════════════════════
// 📄 src/plugin_manager.cpp — اكتشاف ملفات SO / DLL وتحميلها
// ═══════════════════════════════════════════
#include "plugin_manager.hpp"
#include <filesystem>
#include <cstdio>

namespace fs = std::filesystem;

namespace {
bool HasPluginExtension(const fs::path& path) {
#ifdef _WIN32
    return path.extension() == ".dll";
#else
    return path.extension() == ".so";
#endif
}
}

bool PluginManager::LoadSinglePlugin(const std::string& filePath, AppContext& app) {
    // SDL_LoadObject يفتح المكتبة المشتركة وقت التشغيل بدل الربط وقت البناء.
    SDL_SharedObject* handle = SDL_LoadObject(filePath.c_str());
    if (!handle) {
        std::printf("فشل فتح plugin: %s => %s\\n", filePath.c_str(), SDL_GetError());
        return false;
    }

    auto create = reinterpret_cast<CreatePluginFn>(SDL_LoadFunction(handle, "CreatePlugin"));
    auto destroy = reinterpret_cast<DestroyPluginFn>(SDL_LoadFunction(handle, "DestroyPlugin"));
    if (!create || !destroy) {
        std::printf("المكتبة %s لا تصدر CreatePlugin/DestroyPlugin\\n", filePath.c_str());
        SDL_UnloadObject(handle);
        return false;
    }

    IGamePlugin* instance = create();
    if (!instance) {
        std::printf("CreatePlugin أعاد nullptr في %s\\n", filePath.c_str());
        SDL_UnloadObject(handle);
        return false;
    }

    instance->OnLoad(app);
    std::printf("تم تحميل الإضافة: %s\\n", instance->GetName());
    plugins.push_back({filePath, handle, create, destroy, instance});
    return true;
}

bool PluginManager::LoadAllFromDirectory(const std::string& folderPath, AppContext& app) {
    bool loadedAny = false;
    if (!fs::exists(folderPath)) {
        std::printf("مجلد plugins غير موجود: %s\\n", folderPath.c_str());
        return false;
    }

    for (const auto& entry : fs::directory_iterator(folderPath)) {
        if (!entry.is_regular_file() || !HasPluginExtension(entry.path())) {
            continue;
        }
        loadedAny = LoadSinglePlugin(entry.path().string(), app) || loadedAny;
    }
    return loadedAny;
}

void PluginManager::DispatchEvent(const SDL_Event& event, AppContext& app) {
    for (LoadedPlugin& plugin : plugins) {
        plugin.instance->OnEvent(event, app);
    }
}

void PluginManager::UpdateAll(AppContext& app) {
    for (LoadedPlugin& plugin : plugins) {
        plugin.instance->OnUpdate(app);
    }
}

void PluginManager::RenderAllUI(AppContext& app) {
    for (LoadedPlugin& plugin : plugins) {
        plugin.instance->OnRenderUI(app);
    }
}

void PluginManager::UnloadAll(AppContext& app) {
    // نفك الإضافات بترتيب عكسي لأن بعضها قد يعتمد على ترتيب الإنشاء.
    for (auto it = plugins.rbegin(); it != plugins.rend(); ++it) {
        if (it->instance) {
            it->instance->OnUnload(app);
            it->destroy(it->instance);
        }
        if (it->libraryHandle) {
            SDL_UnloadObject(it->libraryHandle);
        }
    }
    plugins.clear();
}

// ═══════════════════════════════════════════
// 📄 plugins/debug_overlay_plugin.cpp — إضافة تعرض FPS
// ═══════════════════════════════════════════
#include "../src/plugin_api.hpp"
#include <cstdio>

class DebugOverlayPlugin final : public IGamePlugin {
    float fps = 0.0f;
    int frames = 0;
    float timer = 0.0f;
public:
    const char* GetName() const override { return "DebugOverlayPlugin"; }

    void OnLoad(AppContext&) override {
        std::printf("DebugOverlayPlugin: جاهزة\\n");
    }

    void OnEvent(const SDL_Event&, AppContext&) override {
        // هذه الإضافة لا تحتاج قراءة أحداث مباشرة في هذا المثال.
    }

    void OnUpdate(AppContext& app) override {
        frames += 1;
        timer += app.deltaTime;
        if (timer >= 1.0f) {
            fps = frames / timer;
            frames = 0;
            timer = 0.0f;
        }
    }

    void OnRenderUI(AppContext&) override {
        ImGui::SetNextWindowPos({12, 12}, ImGuiCond_Always);
        ImGui::Begin("Debug Overlay", nullptr,
            ImGuiWindowFlags_NoDecoration |
            ImGuiWindowFlags_AlwaysAutoResize);
        ImGui::Text("FPS: %.0f", fps);
        ImGui::Text("هذه النافذة جاءت من Plugin محمّل runtime.");
        ImGui::End();
    }

    void OnUnload(AppContext&) override {
        std::printf("DebugOverlayPlugin: cleanup\\n");
    }
};

extern "C" IGamePlugin* CreatePlugin() {
    return new DebugOverlayPlugin();
}

extern "C" void DestroyPlugin(IGamePlugin* plugin) {
    delete plugin;
}

