// ═══════════════════════════════════════════
#include "../src/plugin_api.hpp"
#include <string>
#include <vector>

class ConsolePlugin final : public IGamePlugin {
    char buffer[128] = {};
    std::vector<std::string> messages;
public:
    const char* GetName() const override { return "ConsolePlugin"; }

    void OnLoad(AppContext&) override {
        messages.push_back("ConsolePlugin loaded");
    }

    void OnEvent(const SDL_Event& event, AppContext&) override {
        if (event.type == SDL_EVENT_KEY_DOWN && event.key.key == SDLK_F1) {
            messages.push_back("تم الضغط على F1 من داخل الإضافة");
        }
    }

    void OnUpdate(AppContext&) override {}

    void OnRenderUI(AppContext&) override {
        ImGui::Begin("Plugin Console");
        ImGui::TextWrapped("هذه اللوحة جاءت من مكتبة مشتركة خارج التطبيق الرئيسي.");
        for (const std::string& msg : messages) {
            ImGui::BulletText("%s", msg.c_str());
        }
        if (ImGui::InputText("##console", buffer, sizeof(buffer), ImGuiInputTextFlags_EnterReturnsTrue)) {
            messages.push_back(std::string("> ") + buffer);
            buffer[0] = '\0';
        }
        ImGui::End();
    }

    void OnUnload(AppContext&) override {
        messages.clear();
    }
};

extern "C" IGamePlugin* CreatePlugin() {
    return new ConsolePlugin();
}

extern "C" void DestroyPlugin(IGamePlugin* plugin) {
    delete plugin;
}

