// 📄 src/asset_bundle.hpp — توصيف الحزمة بعد قراءة manifest
// ═══════════════════════════════════════════
#pragma once
#include <string>
#include <vector>
#include <unordered_map>

struct AssetBundle {
    std::string id;
    std::string rootPath;
    std::vector<std::string> textures;
    std::vector<std::string> sounds;
    std::vector<std::string> locales;
    std::unordered_map<std::string, std::string> settings;
    bool loaded = false;
};

// ═══════════════════════════════════════════
// 📄 src/bundle_manager.hpp — واجهة تحميل الحزم من manifests
// ═══════════════════════════════════════════
#pragma once
#include "asset_bundle.hpp"
#include <string>
#include <unordered_map>

class BundleManager {
public:
    bool LoadBundleFromManifest(const std::string& manifestPath);
    bool UnloadBundle(const std::string& bundleId);
    const AssetBundle* FindBundle(const std::string& bundleId) const;
    void RenderUI() const;
    std::size_t Count() const { return bundles.size(); }

private:
    std::unordered_map<std::string, AssetBundle> bundles;
};

// ═══════════════════════════════════════════
// 📄 src/bundle_manager.cpp — parser بسيط لملف manifest
// ═══════════════════════════════════════════
#include "bundle_manager.hpp"
#include <imgui.h>
#include <filesystem>
#include <fstream>
#include <cstdio>

namespace fs = std::filesystem;

namespace {
std::string Trim(const std::string& value) {
    const std::size_t start = value.find_first_not_of(" \t\r\n");
    if (start == std::string::npos) return {};
    const std::size_t end = value.find_last_not_of(" \t\r\n");
    return value.substr(start, end - start + 1);
}
}

bool BundleManager::LoadBundleFromManifest(const std::string& manifestPath) {
    std::ifstream input(manifestPath);
    if (!input) {
        std::printf("فشل فتح manifest: %s\\n", manifestPath.c_str());
        return false;
    }

    AssetBundle bundle;
    bundle.rootPath = fs::path(manifestPath).parent_path().string();

    std::string line;
    while (std::getline(input, line)) {
        line = Trim(line);
        if (line.empty() || line.starts_with('#')) {
            continue;
        }
        const std::size_t equals = line.find('=');
        if (equals == std::string::npos) continue;

        const std::string key = Trim(line.substr(0, equals));
        const std::string value = Trim(line.substr(equals + 1));

        if (key == "id") bundle.id = value;
        else if (key == "texture") bundle.textures.push_back(value);
        else if (key == "sound") bundle.sounds.push_back(value);
        else if (key == "locale") bundle.locales.push_back(value);
        else bundle.settings[key] = value;
    }

    if (bundle.id.empty()) {
        std::printf("manifest بلا id: %s\\n", manifestPath.c_str());
        return false;
    }

    // في مشروع حقيقي هنا سيتم تحميل SDL_Texture و Mix_Chunk وملفات الترجمة فعلياً.
    bundle.loaded = true;
    std::printf("تم تحميل الحزمة %s من %s\\n", bundle.id.c_str(), manifestPath.c_str());
    bundles[bundle.id] = std::move(bundle);
    return true;
}

bool BundleManager::UnloadBundle(const std::string& bundleId) {
    auto it = bundles.find(bundleId);
    if (it == bundles.end()) return false;
    std::printf("تم تفريغ الحزمة %s\\n", bundleId.c_str());
    bundles.erase(it);
    return true;
}

const AssetBundle* BundleManager::FindBundle(const std::string& bundleId) const {
    auto it = bundles.find(bundleId);
    return it == bundles.end() ? nullptr : &it->second;
}

void BundleManager::RenderUI() const {
    ImGui::Begin("Bundle Manager");
    ImGui::Text("عدد الحزم المحملة: %zu", bundles.size());
    for (const auto& [id, bundle] : bundles) {
        if (ImGui::TreeNode(id.c_str())) {
            ImGui::Text("textures: %zu", bundle.textures.size());
            ImGui::Text("sounds: %zu", bundle.sounds.size());
            ImGui::Text("locales: %zu", bundle.locales.size());
            for (const std::string& locale : bundle.locales) {
                ImGui::BulletText("locale => %s", locale.c_str());
            }
            for (const auto& [key, value] : bundle.settings) {
                ImGui::BulletText("%s = %s", key.c_str(), value.c_str());
            }
            ImGui::TreePop();
        }
    }
    ImGui::End();
}

