#pragma once
#include "igame_plugin.hpp"
#include <vector>
#include <memory>
#include <cstdio>

class PluginManager {
    std::vector<std::unique_ptr<IGamePlugin>> plugins;
    BundleManager& bundles;
public:
    explicit PluginManager(BundleManager& bm) : bundles(bm) {}
    void Register(std::unique_ptr<IGamePlugin> p) {
        p->OnLoad(bundles);
        plugins.push_back(std::move(p));
    }
    void UpdateAll(float dt) { for (auto& p : plugins) p->OnUpdate(dt); }
    void RenderAllUI() {
        bundles.RenderUI();
        for (auto& p : plugins) p->OnRenderUI();
    }
    void UnloadAll() {
        for (auto& p : plugins) p->OnUnload(bundles);
        plugins.clear();
    }
};

