// 📄 src/game_lib.hpp — المكتبة المشتركة
// ═══════════════════════════════════════════
#pragma once
#include <SDL3/SDL.h>
#include <imgui.h>
#include <vector>
#include <string>

namespace GameLib {
    // حساب deltaTime
    inline float CalcDelta(Uint64 now, Uint64& last) {
        float dt = (now - last) / (float)SDL_GetPerformanceFrequency();
        last = now;
        return dt;
    }

    // عداد FPS
    struct FpsCounter {
        float fps = 0; int frames = 0; float timer = 0;
        void Update(float dt) {
            frames++; timer += dt;
            if (timer >= 1.0f) { fps = frames / timer; frames = 0; timer = 0; }
        }
    };

    // سجل أحداث
    struct EventLog {
        std::vector<std::string> entries;
        int maxEntries = 50;
        void Add(const char* msg) {
            entries.push_back(msg);
            if ((int)entries.size() > maxEntries) entries.erase(entries.begin());
        }
        void RenderUI(const char* title = "سجل الأحداث") {
            if (!ImGui::Begin(title)) { ImGui::End(); return; }
            for (const auto& e : entries) ImGui::TextUnformatted(e.c_str());
            if (ImGui::Button("مسح")) entries.clear();
            ImGui::End();
        }
    };

    // معلومات النظام
    inline void RenderSystemInfo() {
        if (!ImGui::Begin("معلومات النظام")) { ImGui::End(); return; }
        ImGui::Text("النظام: %s", SDL_GetPlatform());
        ImGui::Text("RAM: %d MB", SDL_GetSystemRAM());
        ImGui::Text("المراكز: %d", SDL_GetNumLogicalCPUCores());
        ImGui::End();
    }
};

