void FrameClock::Tick() {
    const Uint64 now = SDL_GetPerformanceCounter();
    deltaTime = static_cast<float>((now - lastCounter) / static_cast<double>(SDL_GetPerformanceFrequency()));
    lastCounter = now;
}

void Logger::Add(const std::string& line) {
