// 📄 src/bundle_manager.hpp — Bundle: تحميل manifests للموارد
// ═══════════════════════════════════════════
#pragma once
#include <string>
#include <unordered_map>
#include <vector>

struct BundleData {
    std::string id;
    std::vector<std::string> textures;
    std::vector<std::string> sounds;
    std::vector<std::string> settings;
};

class BundleManager {
public:
    bool LoadManifest(const std::string& path);
    bool Unload(const std::string& id);
    const BundleData* Find(const std::string& id) const;
    std::size_t Count() const { return bundles.size(); }

private:
    std::unordered_map<std::string, BundleData> bundles;
};

// ═══════════════════════════════════════════
// 📄 src/bundle_manager.cpp — Bundle parser مبسط
// ═══════════════════════════════════════════
#include "bundle_manager.hpp"
#include <fstream>
#include <cstdio>

bool BundleManager::LoadManifest(const std::string& path) {
    std::ifstream input(path);
    if (!input) return false;

    BundleData bundle;
    std::string line;
    while (std::getline(input, line)) {
        if (line.rfind("id=", 0) == 0) bundle.id = line.substr(3);
        else if (line.rfind("texture=", 0) == 0) bundle.textures.push_back(line.substr(8));
        else if (line.rfind("sound=", 0) == 0) bundle.sounds.push_back(line.substr(6));
        else if (line.rfind("setting=", 0) == 0) bundle.settings.push_back(line.substr(8));
    }

    if (bundle.id.empty()) return false;
    std::printf("bundle loaded => %s\\n", bundle.id.c_str());
    bundles[bundle.id] = std::move(bundle);
    return true;
}

bool BundleManager::Unload(const std::string& id) {
    return bundles.erase(id) > 0;
}

const BundleData* BundleManager::Find(const std::string& id) const {
    auto it = bundles.find(id);
    return it == bundles.end() ? nullptr : &it->second;
}

