// 📄 src/plugin_api.hpp — العقد بين التطبيق والإضافات
// ═══════════════════════════════════════════
#pragma once
#include "bundle_manager.hpp"
#include "game_core.hpp"
#include <SDL3/SDL.h>
#include <imgui.h>

struct RuntimeContext {
    SDL_Window* window = nullptr;
    SDL_Renderer* renderer = nullptr;
    BundleManager* bundles = nullptr;
    GameCore::Logger* logger = nullptr;
    GameCore::EventBus* events = nullptr;
    float deltaTime = 0.0f;
};

struct IPlugin {
    virtual ~IPlugin() = default;
    virtual const char* GetName() const = 0;
    virtual void OnLoad(RuntimeContext& ctx) = 0;
    virtual void OnEvent(const SDL_Event& event, RuntimeContext& ctx) = 0;
    virtual void OnUpdate(RuntimeContext& ctx) = 0;
    virtual void OnRenderUI(RuntimeContext& ctx) = 0;
    virtual void OnUnload(RuntimeContext& ctx) = 0;
};

using CreatePluginFn = IPlugin* (*)();
using DestroyPluginFn = void (*)(IPlugin*);

// ═══════════════════════════════════════════
// 📄 src/plugin_manager.hpp — Plugin: اكتشاف الإضافات
// ═══════════════════════════════════════════
#pragma once
#include "plugin_api.hpp"
#include <string>
#include <vector>

struct PluginSlot {
    std::string path;
    SDL_SharedObject* handle = nullptr;
    DestroyPluginFn destroy = nullptr;
    IPlugin* plugin = nullptr;
};

class PluginManager {
public:
    bool LoadDirectory(const std::string& folder, RuntimeContext& ctx);
    void DispatchEvent(const SDL_Event& event, RuntimeContext& ctx);
    void UpdateAll(RuntimeContext& ctx);
    void RenderAllUI(RuntimeContext& ctx);
    void UnloadAll(RuntimeContext& ctx);
    std::size_t Count() const { return slots.size(); }

private:
    std::vector<PluginSlot> slots;
};

// ═══════════════════════════════════════════
// 📄 src/plugin_manager.cpp — ربط Plugin مع Bundle و Library
// ═══════════════════════════════════════════
#include "plugin_manager.hpp"
#include <filesystem>

namespace fs = std::filesystem;

bool PluginManager::LoadDirectory(const std::string& folder, RuntimeContext& ctx) {
    bool loadedAny = false;
    if (!fs::exists(folder)) return false;
    for (const auto& entry : fs::directory_iterator(folder)) {
#ifdef _WIN32
        const bool valid = entry.path().extension() == ".dll";
#else
        const bool valid = entry.path().extension() == ".so";
#endif
        if (!valid) continue;

        SDL_SharedObject* handle = SDL_LoadObject(entry.path().string().c_str());
        auto create = reinterpret_cast<CreatePluginFn>(SDL_LoadFunction(handle, "CreatePlugin"));
        auto destroy = reinterpret_cast<DestroyPluginFn>(SDL_LoadFunction(handle, "DestroyPlugin"));
        if (!handle || !create || !destroy) continue;

        IPlugin* plugin = create();
        plugin->OnLoad(ctx);
        slots.push_back({entry.path().string(), handle, destroy, plugin});
        loadedAny = true;
    }
    return loadedAny;
}

void PluginManager::DispatchEvent(const SDL_Event& event, RuntimeContext& ctx) {
    for (PluginSlot& slot : slots) slot.plugin->OnEvent(event, ctx);
}

void PluginManager::UpdateAll(RuntimeContext& ctx) {
    for (PluginSlot& slot : slots) slot.plugin->OnUpdate(ctx);
}

void PluginManager::RenderAllUI(RuntimeContext& ctx) {
    for (PluginSlot& slot : slots) slot.plugin->OnRenderUI(ctx);
}

void PluginManager::UnloadAll(RuntimeContext& ctx) {
    for (auto it = slots.rbegin(); it != slots.rend(); ++it) {
        it->plugin->OnUnload(ctx);
        it->destroy(it->plugin);
        SDL_UnloadObject(it->handle);
    }
    slots.clear();
}

