class ParticlePlugin final : public IPlugin {
    int liveParticles = 0;
public:
    const char* GetName() const override { return "ParticlePlugin"; }

    void OnLoad(RuntimeContext& ctx) override {
        ctx.bundles->LoadManifest("assets/bundles/particles/manifest.txt");
        ctx.logger->Add("ParticlePlugin loaded particles_bundle");
    }

    void OnEvent(const SDL_Event& event, RuntimeContext& ctx) override {
        if (event.type == SDL_EVENT_MOUSE_BUTTON_DOWN) {
            liveParticles += 25;
            ctx.events->Publish("spawn_particles");
        }
    }

    void OnUpdate(RuntimeContext& ctx) override {
        liveParticles += static_cast<int>(ctx.deltaTime * 10.0f);
        if (liveParticles > 400) liveParticles = 400;
    }

    void OnRenderUI(RuntimeContext&) override {
        ImGui::Begin("Particles");
        ImGui::Text("liveParticles = %d", liveParticles);
        ImGui::TextWrapped("هذا Plugin يملك السلوك، لكن الملفات نفسها قادمة من bundle منفصل.");
        ImGui::End();
    }

    void OnUnload(RuntimeContext& ctx) override {
        ctx.bundles->Unload("particles_bundle");
        ctx.logger->Add("ParticlePlugin unloaded particles_bundle");
    }
};

