// 📄 src/main.cpp — التطبيق الحقيقي الذي يجمع الأنظمة الثلاثة
// ═══════════════════════════════════════════
#include "bundle_manager.hpp"
#include "game_core.hpp"
#include "plugin_manager.hpp"
#include <SDL3/SDL.h>
#include <imgui.h>
#include <imgui_impl_sdl3.h>
#include <imgui_impl_sdlrenderer3.h>

int main(int, char**) {
    if (!SDL_Init(SDL_INIT_VIDEO)) return 1;
    SDL_Window* window = SDL_CreateWindow("Full Pattern", 1280, 720, SDL_WINDOW_RESIZABLE);
    SDL_Renderer* renderer = SDL_CreateRenderer(window, nullptr);

    IMGUI_CHECKVERSION();
    ImGui::CreateContext();
    ImGui_ImplSDL3_InitForSDLRenderer(window, renderer);
    ImGui_ImplSDLRenderer3_Init(renderer);

    GameCore::FrameClock clock;
    GameCore::Logger logger;
    GameCore::EventBus eventBus;
    BundleManager bundles;
    clock.Start();

    RuntimeContext ctx;
    ctx.window = window;
    ctx.renderer = renderer;
    ctx.bundles = &bundles;
    ctx.logger = &logger;
    ctx.events = &eventBus;

    PluginManager plugins;
    plugins.LoadDirectory("plugins", ctx);

    bool running = true;
    while (running) {
        SDL_Event event;
        while (SDL_PollEvent(&event)) {
            ImGui_ImplSDL3_ProcessEvent(&event);
            if (event.type == SDL_EVENT_QUIT) running = false;
            plugins.DispatchEvent(event, ctx);
        }

        clock.Tick();
        ctx.deltaTime = clock.deltaTime;

        ImGui_ImplSDLRenderer3_NewFrame();
        ImGui_ImplSDL3_NewFrame();
        ImGui::NewFrame();

        ImGui::Begin("Overview");
        ImGui::Text("deltaTime: %.4f", ctx.deltaTime);
        ImGui::Text("plugins: %zu", plugins.Count());
        ImGui::Text("bundles: %zu", bundles.Count());
        ImGui::Text("logs: %zu", logger.lines.size());
        ImGui::End();

        plugins.UpdateAll(ctx);
        plugins.RenderAllUI(ctx);

        ImGui::Begin("Logger");
        for (const std::string& line : logger.lines) ImGui::BulletText("%s", line.c_str());
        ImGui::End();

        ImGui::Render();
        SDL_SetRenderDrawColor(renderer, 20, 22, 30, 255);
        SDL_RenderClear(renderer);
        ImGui_ImplSDLRenderer3_RenderDrawData(ImGui::GetDrawData());
        SDL_RenderPresent(renderer);
    }

    plugins.UnloadAll(ctx);
    ImGui_ImplSDLRenderer3_Shutdown();
    ImGui_ImplSDL3_Shutdown();
    ImGui::DestroyContext();
    SDL_DestroyRenderer(renderer);
    SDL_DestroyWindow(window);
    SDL_Quit();
    return 0;
}

